#include <stdio.h>
#include <string.h>
#include <math.h>
#include <stdlib.h>
#include <CL/cl.h>
#include <iostream>
#include <fstream>
#include <vector>
#include <string>

// Define the Node structure matching the original
struct Node {
    int starting;
    int no_of_edges;
};

// Helper to check OpenCL errors
void checkError(cl_int err, const char* msg) {
    if (err != CL_SUCCESS) {
        fprintf(stderr, "Error: %s (%d)\n", msg, err);
        exit(1);
    }
}

// Helper to read file content for kernel source
std::string fileToString(const std::string& filename) {
    std::ifstream f(filename.c_str(), std::ifstream::in | std::ifstream::binary);
    if (!f.is_open()) {
        // Fallback if Kernels.cl is not found, we might need to define kernels inline or assume standard path
        // For this translation, we assume the build environment provides "Kernels.cl" or we use the inline logic
        // However, to be self-contained as per "translate source code", we will try to load "Kernels.cl"
        // which should be generated or present. If not, we throw.
        throw std::string("Unable to open kernel file: " + filename);
    }
    std::string content((std::istreambuf_iterator<char>(f)), std::istreambuf_iterator<char>();
    return content;
}

int main(int argc, char** argv) {
    int no_of_nodes = 0;
    int edge_list_size = 0;
    char *input_f;

    if (argc != 3) {
        fprintf(stderr, "Usage: %s <num_threads> <input_file>\n", argv[0]);
        exit(0);
    }

    // num_threads argument is ignored in OpenCL as work group size is managed differently,
    // but we parse it to maintain argument compatibility.
    int num_omp_threads = atoi(argv[1]);
    input_f = argv[2];

    printf("Reading File\n");

    FILE *fp = fopen(input_f, "r");
    if (!fp) {
        printf("Error Reading graph file\n");
        return 1;
    }

    int source = 0;
    fscanf(fp, "%d", &no_of_nodes);

    Node* h_graph_nodes = (Node*) malloc(sizeof(Node) * no_of_nodes);
    char* h_graph_mask = (char*) malloc(sizeof(char) * no_of_nodes);
    char* h_updating_graph_mask = (char*) malloc(sizeof(char) * no_of_nodes);
    char* h_graph_visited = (char*) malloc(sizeof(char) * no_of_nodes);

    int start, edgeno;
    for (unsigned int i = 0; i < no_of_nodes; i++) {
        fscanf(fp, "%d %d", &start, &edgeno);
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i] = 0; // false
        h_updating_graph_mask[i] = 0; // false
        h_graph_visited[i] = 0; // false
    }

    fscanf(fp, "%d", &source);

    h_graph_mask[source] = 1; // true
    h_graph_visited[source] = 1; // true

    fscanf(fp, "%d", &edge_list_size);

    int id, cost;
    int* h_graph_edges = (int*) malloc(sizeof(int) * edge_list_size);
    for (int i = 0; i < edge_list_size; i++) {
        fscanf(fp, "%d", &id);
        fscanf(fp, "%d", &cost);
        h_graph_edges[i] = id;
    }

    if (fp) fclose(fp);

    int* h_cost = (int*) malloc(sizeof(int) * no_of_nodes);
    for (int i = 0; i < no_of_nodes; i++)
        h_cost[i] = -1;
    h_cost[source] = 0;

    printf("Start traversing the tree\n");

    // OpenCL Setup
    cl_int err;
    cl_platform_id platform;
    cl_device_id device;
    cl_context context;
    cl_command_queue queue;
    cl_program program;
    cl_kernel kernel1, kernel2;

    // Get Platform and Device
    cl_uint numPlatforms;
    err = clGetPlatformIDs(0, NULL, &numPlatforms);
    checkError(err, "clGetPlatformIDs");
    err = clGetPlatformIDs(1, &platform, NULL);
    checkError(err, "clGetPlatformIDs");

    err = clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 1, &device, NULL);
    checkError(err, "clGetDeviceIDs");

    // Create Context and Queue
    context = clCreateContext(NULL, 1, &device, NULL, NULL, &err);
    checkError(err, "clCreateContext");

    queue = clCreateCommandQueue(context, device, 0, &err);
    checkError(err, "clCreateCommandQueue");

    // Create Buffers
    cl_mem d_graph_nodes = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, sizeof(Node) * no_of_nodes, h_graph_nodes, &err);
    checkError(err, "clCreateBuffer d_graph_nodes");

    cl_mem d_graph_edges = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, sizeof(int) * edge_list_size, h_graph_edges, &err);
    checkError(err, "clCreateBuffer d_graph_edges");

    cl_mem d_graph_mask = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(char) * no_of_nodes, h_graph_mask, &err);
    checkError(err, "clCreateBuffer d_graph_mask");

    cl_mem d_updating_graph_mask = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(char) * no_of_nodes, h_updating_graph_mask, &err);
    checkError(err, "clCreateBuffer d_updating_graph_mask");

    cl_mem d_graph_visited = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(char) * no_of_nodes, h_graph_visited, &err);
    checkError(err, "clCreateBuffer d_graph_visited");

    cl_mem d_cost = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(int) * no_of_nodes, h_cost, &err);
    checkError(err, "clCreateBuffer d_cost");

    cl_mem d_over = clCreateBuffer(context, CL_MEM_READ_WRITE, sizeof(char), NULL, &err);
    checkError(err, "clCreateBuffer d_over");

    // Load Kernel Source
    std::string kernelSource;
    try {
        kernelSource = fileToString("Kernels.cl");
    } catch (...) {
        // If Kernels.cl is missing, we might need to define it inline or the build system ensures it exists.
        // Assuming the build system provides translated_0.cl as the kernel source file renamed to Kernels.cl
        // Or we try to read "translated_0.cl" if the build doesn't rename it.
        // Given the constraints, we assume "Kernels.cl" is available as per Infrastructure File 2 default.
        fprintf(stderr, "Error: Could not load Kernels.cl. Ensure it is present.\n");
        return 1;
    }

    const char* src = kernelSource.c_str();
    program = clCreateProgramWithSource(context, 1, &src, NULL, &err);
    checkError(err, "clCreateProgramWithSource");

    err = clBuildProgram(program, 1, &device, NULL, NULL, NULL);
    if (err != CL_SUCCESS) {
        size_t logSize;
        clGetProgramBuildInfo(program, device, CL_PROGRAM_BUILD_LOG, 0, NULL, &logSize);
        char* log = (char*)malloc(logSize);
        clGetProgramBuildInfo(program, device, CL_PROGRAM_BUILD_LOG, logSize, log, NULL);
        fprintf(stderr, "Build Error: %s\n", log);
        free(log);
        exit(1);
    }

    kernel1 = clCreateKernel(program, "BFS_1", &err);
    checkError(err, "clCreateKernel BFS_1");
    kernel2 = clCreateKernel(program, "BFS_2", &err);
    checkError(err, "clCreateKernel BFS_2");

    // Set Arguments for Kernel 1
    clSetKernelArg(kernel1, 0, sizeof(cl_mem), &d_graph_nodes);
    clSetKernelArg(kernel1, 1, sizeof(cl_mem), &d_graph_edges);
    clSetKernelArg(kernel1, 2, sizeof(cl_mem), &d_graph_mask);
    clSetKernelArg(kernel1, 3, sizeof(cl_mem), &d_updating_graph_mask);
    clSetKernelArg(kernel1, 4, sizeof(cl_mem), &d_graph_visited);
    clSetKernelArg(kernel1, 5, sizeof(cl_mem), &d_cost);
    clSetKernelArg(kernel1, 6, sizeof(int), &no_of_nodes);

    // Set Arguments for Kernel 2
    clSetKernelArg(kernel2, 0, sizeof(cl_mem), &d_graph_mask);
    clSetKernelArg(kernel2, 1, sizeof(cl_mem), &d_updating_graph_mask);
    clSetKernelArg(kernel2, 2, sizeof(cl_mem), &d_graph_visited);
    clSetKernelArg(kernel2, 3, sizeof(cl_mem), &d_over);
    clSetKernelArg(kernel2, 4, sizeof(int), &no_of_nodes);

    char h_over;
    char stop;
    int k = 0;

    size_t globalSize[1] = { (size_t)no_of_nodes };
    size_t localSize[1] = { 256 }; // Default block size, adjust if needed

    do {
        stop = 0;
        h_over = 0;
        clEnqueueWriteBuffer(queue, d_over, CL_TRUE, 0, sizeof(char), &h_over, 0, NULL, NULL);

        // Run BFS_1
        clEnqueueNDRangeKernel(queue, kernel1, 1, NULL, globalSize, localSize, 0, NULL, NULL);

        // Run BFS_2
        clEnqueueNDRangeKernel(queue, kernel2, 1, NULL, globalSize, localSize, 0, NULL, NULL);

        clEnqueueReadBuffer(queue, d_over, CL_TRUE, 0, sizeof(char), &h_over, 0, NULL, NULL);

        if (h_over) stop = 1;
        k++;
    } while (stop);

    // Read back results
    clEnqueueReadBuffer(queue, d_cost, CL_TRUE, 0, sizeof(int) * no_of_nodes, h_cost, 0, NULL, NULL);
    clFinish(queue);

    printf("Result stored in result.txt\n");

    FILE *fpo = fopen("result.txt", "w");
    for (int i = 0; i < no_of_nodes; i++) {
        fprintf(fpo, "%d) cost:%d\n", i, h_cost[i]);
    }
    fclose(fpo);
    printf("Result stored in result.txt\n");

    // Cleanup
    clReleaseMemObject(d_graph_nodes);
    clReleaseMemObject(d_graph_edges);
    clReleaseMemObject(d_graph_mask);
    clReleaseMemObject(d_updating_graph_mask);
    clReleaseMemObject(d_graph_visited);
    clReleaseMemObject(d_cost);
    clReleaseMemObject(d_over);
    clReleaseKernel(kernel1);
    clReleaseKernel(kernel2);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);

    free(h_graph_nodes);
    free(h_graph_edges);
    free(h_graph_mask);
    free(h_updating_graph_mask);
    free(h_graph_visited);
    free(h_cost);

    return 0;
}
